const response = $input.first().json;

if (response.error) {
  throw new Error(`Gemini API error: ${response.error.code} — ${response.error.message}`);
}

const candidates = response.candidates;
if (!candidates || candidates.length === 0) {
  const blockReason = response.promptFeedback?.blockReason;
  throw new Error(`Gemini returned no candidates. Block reason: ${blockReason || 'unknown'}`);
}

const candidate = candidates[0];
const finishReason = candidate.finishReason;
if (finishReason && finishReason !== 'STOP' && finishReason !== 'MAX_TOKENS') {
  throw new Error(`Gemini stopped unexpectedly: finishReason=${finishReason}`);
}

const parts = candidate.content?.parts || [];
const rawText = parts.filter(p => p.text).map(p => p.text).join('').trim();

if (!rawText) {
  throw new Error('Gemini returned empty content.');
}

const cleaned = rawText
  .replace(/^```json\s*/i, '')
  .replace(/^```\s*/i, '')
  .replace(/\s*```$/i, '')
  .trim();

let digest;
try {
  digest = JSON.parse(cleaned);
} catch (e) {
  throw new Error(`Failed to parse Gemini JSON: ${e.message}. Raw: ${cleaned.substring(0, 500)}`);
}

if (!digest.stories || !Array.isArray(digest.stories)) {
  throw new Error('Invalid digest — missing stories array');
}

digest.stories.sort((a, b) => {
  if (a.importance === 'high' && b.importance !== 'high') return -1;
  if (b.importance === 'high' && a.importance !== 'high') return 1;
  return 0;
});

const groundingMeta = candidate.groundingMetadata;
if (groundingMeta?.webSearchQueries) {
  digest._searchQueries = groundingMeta.webSearchQueries;
}

return [{ json: digest }];

const digest = $input.first().json;

const SOURCE_COLORS = {
  'HousingWire': '#1a3a5c',
  'Mortgage News Daily': '#1a6b8a',
  'MBS Live': '#b5451b',
  'National Mortgage Professional': '#6b3fa0',
  'Federal Reserve': '#2d6a4f',
  'CFPB': '#1a472a',
  'Freddie Mac': '#003087',
  'Fannie Mae': '#00579b',
  'Mortgage Bankers Association': '#8b1a1a',
  'National Association of Realtors': '#005eb8',
  'Bloomberg': '#ff6600',
  'Wall Street Journal': '#000000',
};

const CATEGORY_LABELS = {
  rates: '📈 RATES', mbs: '📊 MBS', housing: '🏠 HOUSING',
  fed: '🏦 FEDERAL RESERVE', regulatory: '📋 REGULATORY',
  gse: '🏛️ GSE', lender: '🏢 LENDER NEWS', economy: '💼 ECONOMY',
};

const getSourceColor = (source) => {
  for (const [key, color] of Object.entries(SOURCE_COLORS)) {
    if (source.toLowerCase().includes(key.toLowerCase())) return color;
  }
  return '#334155';
};

const rateRows = (digest.marketSnapshot?.rates || []).map(r => {
  const changeColor = r.change && r.change.startsWith('+') ? '#ef4444' : r.change && r.change.startsWith('-') ? '#22c55e' : '#64748b';
  return `<tr>
    <td style="padding:6px 12px 6px 0;font-family:'Courier New',monospace;font-size:11px;color:#94a3b8;letter-spacing:0.06em;border-bottom:1px solid #1e293b;">${r.label}</td>
    <td style="padding:6px 0;font-family:'Courier New',monospace;font-size:13px;color:#e2e8f0;font-weight:700;border-bottom:1px solid #1e293b;">${r.value}</td>
    <td style="padding:6px 0 6px 12px;font-family:'Courier New',monospace;font-size:11px;color:${changeColor};border-bottom:1px solid #1e293b;text-align:right;">${r.change || ''}</td>
  </tr>`;
}).join('');

const storyCards = digest.stories.map((story) => {
  const borderColor = getSourceColor(story.source);
  const isTop = story.importance === 'high';
  const categoryLabel = CATEGORY_LABELS[story.category] || (story.category || '').toUpperCase();

  const keyPointsHtml = story.keyPoints?.length
    ? `<ul style="margin:10px 0 0;padding-left:18px;">${story.keyPoints.map(p =>
        `<li style="font-size:12px;color:#94a3b8;line-height:1.6;margin-bottom:4px;">${p}</li>`).join('')}</ul>`
    : '';

  const effects = story.effects;
  const effectsHtml = effects?.hasEffects
    ? `<table cellpadding="0" cellspacing="0" width="100%" style="margin-top:14px;border-top:1px solid #1e3a5f;padding-top:12px;">
        <tr>
          <td width="50%" valign="top" style="padding-right:10px;">
            <p style="margin:0 0 6px;font-size:9px;font-family:'Courier New',monospace;color:#c9a84c;letter-spacing:0.1em;">⚡ 1ST ORDER EFFECTS</p>
            <ul style="margin:0;padding-left:14px;">${(effects.firstOrder || []).map(e =>
              `<li style="font-size:11px;color:#94a3b8;line-height:1.6;margin-bottom:4px;">${e}</li>`).join('')}</ul>
          </td>
          <td width="50%" valign="top" style="padding-left:10px;border-left:1px solid #1e293b;">
            <p style="margin:0 0 6px;font-size:9px;font-family:'Courier New',monospace;color:#6b7fa8;letter-spacing:0.1em;">〜 2ND ORDER EFFECTS</p>
            <ul style="margin:0;padding-left:14px;">${(effects.secondOrder || []).map(e =>
              `<li style="font-size:11px;color:#64748b;line-height:1.6;margin-bottom:4px;">${e}</li>`).join('')}</ul>
          </td>
        </tr>
      </table>`
    : '';

  const linkHtml = story.sourceUrl
    ? `<a href="${story.sourceUrl}" style="font-size:11px;color:#c9a84c;text-decoration:none;font-family:'Courier New',monospace;">Read full story →</a>`
    : '';

  return `<div style="border-left:4px solid ${borderColor};padding:16px 18px;margin-bottom:16px;background:#0d1520;border-radius:0 6px 6px 0;">
    <div style="margin-bottom:8px;">
      <span style="display:inline-block;padding:2px 8px;background:${borderColor};color:white;font-size:9px;font-family:'Courier New',monospace;letter-spacing:0.08em;border-radius:3px;">${story.source.toUpperCase()}</span>
      ${isTop ? ' <span style="font-size:9px;color:#c9a84c;font-family:Courier New,monospace;letter-spacing:0.08em;font-weight:700;">▲ TOP STORY</span>' : ''}
      ${categoryLabel ? ` <span style="font-size:9px;color:#475569;font-family:Courier New,monospace;">${categoryLabel}</span>` : ''}
    </div>
    <p style="margin:0 0 8px;font-size:14px;font-weight:700;color:#e2e8f0;line-height:1.4;">${story.headline}</p>
    <p style="margin:0 0 10px;font-size:13px;color:#94a3b8;line-height:1.65;">${story.summary}</p>
    ${keyPointsHtml}
    ${effectsHtml}
    ${linkHtml ? `<div style="margin-top:12px;">${linkHtml}</div>` : ''}
  </div>`;
}).join('');

const watchItems = (digest.watchList || []).map(item =>
  `<li style="font-size:13px;color:#94a3b8;line-height:1.7;margin-bottom:6px;">${item}</li>`
).join('');

const UNSUBSCRIBE_WEBHOOK = 'https://YOUR-N8N-INSTANCE/webhook/digest-unsubscribe';

const html = `<!DOCTYPE html>
<html lang="en">
<head><meta charset="UTF-8"><meta name="viewport" content="width=device-width,initial-scale=1.0">
<title>${digest.subject || 'Daily Mortgage Digest'}</title>
</head>
<body style="margin:0;padding:0;background:#080e17;font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',sans-serif;">
<table width="100%" cellpadding="0" cellspacing="0" style="background:#080e17;"><tr><td align="center" style="padding:24px 16px;">
<table width="600" cellpadding="0" cellspacing="0" style="max-width:600px;width:100%;">

  <tr><td style="background:#0a0f1a;border:1px solid #1e293b;border-bottom:3px solid #c9a84c;border-radius:8px 8px 0 0;padding:24px 28px;">
    <table width="100%" cellpadding="0" cellspacing="0"><tr>
      <td><p style="margin:0 0 4px;font-size:10px;font-family:'Courier New',monospace;color:#c9a84c;letter-spacing:0.14em;">DAILY BRIEFING</p>
        <h1 style="margin:0 0 4px;font-size:22px;font-weight:800;color:white;letter-spacing:-0.02em;">Mortgage &amp; Real Estate Digest</h1>
        <p style="margin:0;font-size:11px;font-family:'Courier New',monospace;color:#475569;">${digest.date}</p></td>
      <td align="right" style="vertical-align:middle;"><span style="font-size:32px;">🏠</span></td>
    </tr></table>
  </td></tr>

  <tr><td style="background:#0d1520;border:1px solid #1e293b;border-top:none;padding:22px 28px;">
    <p style="margin:0 0 6px;font-size:10px;font-family:'Courier New',monospace;color:#c9a84c;letter-spacing:0.12em;">MARKET SNAPSHOT</p>
    <p style="margin:0 0 18px;font-size:13px;color:#cbd5e1;line-height:1.7;">${digest.marketSnapshot?.narrative || ''}</p>
    <table cellpadding="0" cellspacing="0" width="100%">${rateRows}</table>
  </td></tr>

  <tr><td style="background:#080e17;border:1px solid #1e293b;border-top:none;padding:22px 28px;">
    <p style="margin:0 0 16px;font-size:10px;font-family:'Courier New',monospace;color:#c9a84c;letter-spacing:0.12em;">TODAY'S TOP STORIES</p>
    ${storyCards}
  </td></tr>

  <tr><td style="background:#0d1520;border:1px solid #1e293b;border-top:none;padding:20px 28px;">
    <p style="margin:0 0 10px;font-size:10px;font-family:'Courier New',monospace;color:#c9a84c;letter-spacing:0.12em;">WHAT TO WATCH TODAY</p>
    <ul style="margin:0;padding-left:18px;">${watchItems}</ul>
    ${digest.closingNote ? `<p style="margin:14px 0 0;font-size:12px;color:#475569;font-style:italic;line-height:1.6;">${digest.closingNote}</p>` : ''}
  </td></tr>

  <tr><td style="background:#0a0f1a;border:1px solid #1e293b;border-top:none;border-radius:0 0 8px 8px;padding:16px 28px;text-align:center;">
    <p style="margin:0 0 4px;font-size:11px;color:#e2e8f0;font-weight:600;">Mortgage Digest — JWH Finance</p>
    <p style="margin:0 0 8px;font-size:10px;font-family:'Courier New',monospace;color:#475569;">mortgage-digest@jwhfinance.com</p>
    <p style="margin:0 0 6px;font-size:10px;font-family:'Courier New',monospace;color:#334155;letter-spacing:0.04em;">Sources: HousingWire · MND · MBS Live · NMP · Fed · CFPB · Freddie Mac · Fannie Mae · MBA · NAR · Bloomberg · WSJ</p>
    <p style="margin:0;font-size:10px;font-family:'Courier New',monospace;"><a href="${UNSUBSCRIBE_WEBHOOK}?email={{subscriber_email}}" style="color:#475569;text-decoration:underline;">Unsubscribe</a></p>
  </td></tr>

</table></td></tr></table>
</body></html>`;

return [{ json: { html, subject: digest.subject || `🏠 Mortgage Digest — ${digest.date}`, digest } }];

const body = $input.first().json.body || $input.first().json;

const email = (body.email || '').toLowerCase().trim();
const firstName = (body.firstName || '').trim();
const lastName = (body.lastName || '').trim();
const company = (body.company || '').trim();
const role = (body.role || '').trim();
const roleOther = (body.roleOther || '').trim();
const phone = (body.phone || '').trim();

// Required field validation
if (!email || !/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email)) {
  return [{ json: { valid: false, error: 'Valid email address is required.' } }];
}
if (!firstName) {
  return [{ json: { valid: false, error: 'First name is required.' } }];
}
if (!lastName) {
  return [{ json: { valid: false, error: 'Last name is required.' } }];
}
if (!role) {
  return [{ json: { valid: false, error: 'Please select your role.' } }];
}

return [{ json: {
  valid: true,
  email,
  firstName,
  lastName,
  fullName: `${firstName} ${lastName}`,
  company,
  role,
  roleOther,
  phone,
  subscribedAt: new Date().toISOString(),
  active: true,
  send_count: 0,
  last_sent_at: '',
  source: 'landing_page'
} }];
